if (! function_exists('emoji_sparkline')) {
    function emoji_sparkline($values, $style = null, $width = null)
    {
        $vals = $values;
        $style = $style ?? 'heat';
        $maxWidth = $width ?? 0;

        if (empty($vals)) {
            return json_encode(['error' => 'No values provided']);
        }

        // Downsample if needed
        $n = count($vals);
        if ($maxWidth > 0 && $n > $maxWidth) {
            $downsampled = [];
            for ($i = 0; $i < $maxWidth; $i++) {
                $idx = (int)round($i * ($n - 1) / ($maxWidth - 1));
                $downsampled[] = $vals[$idx];
            }
            $vals = $downsampled;
            $n = count($vals);
        }

        // Style definitions (8 levels)
        $styles = [
            'heat' => ['⬜', '🟦', '🟩', '🟨', '🟧', '🟥', '🔴', '🔥'],
            'mono' => ['⬜','🔵','🔵','🔵','🔵','🔵','🔵','🔵'],
            'gradient' => ['⬜','🟪','🟦','🟩','🟨','🟧','🟥','💜'],
            'mood' => ['😞','😟','😐','🙂','😊','😄','🤩','🥳'],
            'arrow' => ['⬇️','⬇️','↘️','➡️','➡️','↗️','⬆️','⬆️'],
        ];

        if (!isset($styles[$style])) {
            $style = 'heat';
        }
        $palette = $styles[$style];
        $levels = count($palette);

        // Normalize values to 0..1
        $min = min($vals);
        $max = max($vals);
        $range = $max - $min;
        if ($range == 0) $range = 1;

        // Map each value to an emoji
        $sparkline = '';
        $mapped = [];
        foreach ($vals as $v) {
            $frac = ($v - $min) / $range;
            $idx = (int)round($frac * ($levels - 1));
            $idx = max(0, min($levels - 1, $idx));
            $sparkline .= $palette[$idx];
            $mapped[] = ['value' => $v, 'level' => $idx, 'emoji' => $palette[$idx]];
        }

        // Compute trend
        $trend = 'stable';
        if ($n >= 2) {
            $firstHalf = array_slice($vals, 0, (int)($n / 2));
            $secondHalf = array_slice($vals, (int)($n / 2));
            $firstAvg = array_sum($firstHalf) / count($firstHalf);
            $secondAvg = array_sum($secondHalf) / count($secondHalf);
            $diff = $secondAvg - $firstAvg;
            if ($diff > $range * 0.1) $trend = 'increasing';
            elseif ($diff < -$range * 0.1) $trend = 'decreasing';
        }

        // Interpret style
        $styleNames = [
            'heat' => 'Heat map (cold→hot)',
            'mono' => 'Monochrome intensity',
            'gradient' => 'Rainbow gradient',
            'mood' => 'Mood meter',
            'arrow' => 'Direction arrows'
        ];

        return json_encode([
            'sparkline' => $sparkline,
            'style' => $style,
            'style_name' => $styleNames[$style] ?? $style,
            'data_points' => $n,
            'min' => $min,
            'max' => $max,
            'trend' => $trend,
            'mapped' => $mapped,
            'next_steps' => [
                'Compose with data_simulator to generate and visualize data.',
                'Compose with data_normalizer before sparkline for scaled values.',
                'Compose with emoji_art_renderer to add as part of a larger display.',
            ],
        ]);
    }
}
